// test/regression/regression-runner.js (30 LOC)
'use strict';

const fs = require('fs');
const path = require('path');
const router = require('../../hermes-discord/model-router');

const corpus = require('../../test/thai-test-corpus.json');
const args = require('minimist')(process.argv.slice(2));

const ordering = args.ordering || 'default';
const runs = parseInt(args.runs || '10', 10);
const outputPath = args.output || 'test/regression/results.json';

function getBackendOrder(variant) {
  let order = router.status().order.slice();
  if (variant === 'reversed') order = order.reverse();
  if (variant === 'shuffled') {
    const seeded = () => {
      const x = Math.sin(42) * 10000;
      return x - Math.floor(x);
    };
    for (let i = order.length - 1; i > 0; i--) {
      const j = Math.floor(seeded() * (i + 1));
      [order[i], order[j]] = [order[j], order[i]];
    }
  }
  return order;
}

const results = [];
const backends = getBackendOrder(ordering);

for (const phrase of corpus) {
  for (let run = 0; run < runs; run++) {
    const t0 = Date.now();
    const key = router.thaiCanonicalize(phrase.input || '');
    const hashObj = { key: router.routingKey([{role:'user', content: key}], {}) };
    const selected = router.pickBackendByKey(hashObj.key, backends);
    const latencyMs = Date.now() - t0;
    results.push({
      phrase: phrase.id,
      run,
      key: hashObj.key,
      backend: selected,
      latencyMs
    });
  }
}

fs.writeFileSync(outputPath, JSON.stringify(results, null, 2));
console.log(`Wrote ${results.length} results to ${outputPath}`);
